(this["webpackJsonpbrown-edu-orchestra"]=this["webpackJsonpbrown-edu-orchestra"]||[]).push([[37],{117:function(e,n,a){"use strict";a.r(n),a.d(n,"readingTime",(function(){return r})),a.d(n,"meta",(function(){return i})),a.d(n,"default",(function(){return l})),a.d(n,"tableOfContents",(function(){return h})),a.d(n,"frontMatter",(function(){return u}));var t=a(11),o=(a(2),a(1)),r={text:"4 min read",minutes:3.33,time:199800,words:666},i={title:"A Letter from the 2025-2026 President",subtitle:"Eliana Alweis '26",author:{name:"Nathan Throneburg",uid:"nathanthroneburg1",email:"nathan_throneburg@brown.edu",browndirectory:"aaa1fd43-ef70-45fc-a5b8-25cbda54cdce"},topic:"Blog",date:"2026-05-26",image:{url:"/images/uploads/buo-5.png"},path:"/news/2026-05-26/a-letter-from-the-2025-2026-president"},s={meta:i};function l(e){var n=e.components,a=Object(t.a)(e,["components"]);return Object(o.a)("wrapper",Object.assign({},s,a,{components:n,mdxType:"MDXLayout"}),Object(o.a)("p",null,"To our BUO Community,"),Object(o.a)("p",null,"My name is Eliana Alweis and I have had the pleasure of serving as the Brown University Orchestra president for the 2025\u20132026 term. It was a very exciting and busy season for us and it has been a joy and honor for me to carry the responsibilities of board leadership this year.\xa0"),Object(o.a)("p",null,"Under Mark\u2019s baton, we performed a variety of repertoire including classical and contemporary works. We hit the ground running in the fall with Rite of Spring (Stravinsky), Daphnis and Chloe Suite No. 2 (Ravel), and the world premiere of Tee Gotsch Portrait of a Cardinal. In the spring we played Symphonic Dances (Rachmaninoff ), Three Black Kings (Ellington), and Brahms Piano Concerto I in D minor. We had the privilege to play with soloists including Daniel Xu, Yiyun Li, Ziqi Fang, Timo Volbrecht, and Saleem Ashkar. Student interviews are on our website."),Object(o.a)("p",null,"This year we welcomed over 110 musicians to the orchestra with four concerts on campus, three in Canada, and one at Carnegie Hall. We continued our tradition of selling out the Lindemann main hall for all of our campus performances, welcoming Brown and Providence community members. During our Canada tour, we had the opportunity to perform at Palais Moncalm, Dominion Chalmers Centre, and the Notre Dame Basilica of Montreal while exploring Quebec City, Ottawa, and Montreal thanks to a partnership with Music Celebrations International. To end our 2025\u20132026 season, we had the privilege to play at Carnegie Hall with a lovely audience, even including President Paxson. Thank you to Mark Seto, Erica Giokas, Jeremy Worthington, Jen Vieira, and Drew Moser, who helped make these opportunities possible.\xa0"),Object(o.a)("p",null,"At our annual BUO Ball, we welcomed over 150 students and featured 12 different performing groups. We held multiple community bonding events within BUO including a game and movie nights, as well as our annual senior farewell potluck. During Lindemann equipment moves we continued our new tradition of flatbread dinners. We look forward to the future ahead and the opportunity to continue fostering a community in BUO with traditions new and old.\xa0"),Object(o.a)("p",null,"Thank you to our (largest ever?) BUO board who helped make the orchestra run so smoothly. First, a tremendous thank you to my vice president, Anne, who shouldered great responsibilities many of which she learned about post election. Next, thank you Tee who moved from the role of president to shouldering the work of tour manager. Thank you to the heads of each subcommittee who led each of their teams with grace and poise: Daniel X, Henry, Ian, Jabin, and Nathan. And last, but not least, thank you to everyone who made up the body of each of our 12 subcommittees for their ideas and dedication: Abe, Allie, Alyssa, Andy, Audrey, Brendon, Brian, Cami, Camille, Charlotte C, Daniel B, Emily, Emma, Grace, Hannah B, Hannah Z, Iris, Jaden, James, Jasmine, Joanne, Joseph, JR, Kajsa, Leeah, Luke, Matt, Megan, Michelle, Naomi, Ryan, and Zo\xeb.\xa0"),Object(o.a)("p",null,"This year\u2019s senior class has held a special place in my heart. It was a pleasure to make music with them during my time at Brown and I am grateful for our shared moments and memories. As Mamma Mia says, \u201cThank you for the music, the songs I\u2019m singing\u2026 for all the joy they\u2019re bringing\u2026 for giving it to me.\u201d Best of luck on your future endeavors: Andrew F, Andrew G, Athina, Austin J, Austin X, Barron, Chris, Collin, Daniel X, Erica, Ethan P, Grace M, Hannah Z, Henry, Jimmy C, Kelly, Leeah, Meg, Milan, Moonhee, Phoebe, Ryan, Tee, Yiyun, Ziqi, and Zo\xeb."),Object(o.a)("p",null,"While we say goodbye to our seniors, it is important to look toward the future! As such, I would like to congratulate Anne and Jabin, our president and vice president elect respectively. I know they will do amazing things next year and look forward to seeing their plans come to fruition.\xa0"),Object(o.a)("p",null,"With happy thoughts and well wishes,\xa0"),Object(o.a)("p",null,"Eliana Alweis (she/her \u201826)"))}l.isMDXComponent=!0;var h=function(){return[]},u={}}}]);
